usageExamples:
import { IconButton } from '@zephyr/ui-react';
import { MaterialIcon } from '@zephyr/icons-material';
<IconButton icon={<MaterialIcon name='search' />} label='Search' />

import { Progress } from '@zephyr/ui-react';
<Progress value={65} tone='primary' showValue />
<Progress label='Uploading' />

import { ComboBox } from '@zephyr/ui-react';
<ComboBox
  options={[{value:'react',label:'React'},{value:'vue',label:'Vue'}]}
  value={framework}
  onChange={setFramework}
  placeholder='Select framework'
/>

import { AlertDialog } from '@zephyr/ui-react';
<AlertDialog
  open={showConfirm}
  onClose={() => setShowConfirm(false)}
  title='Delete project?'
  description='This cannot be undone.'
  confirmLabel='Delete'
  confirmTone='danger'
  onConfirm={handleDelete}
/>
